import { ElapsedTimer, GameRunningStatus, useElapsedTime } from '@kyokuya/react-game-core'
import {
  KyokuyaSudoku,
  KyokuyaSudokuActionType,
  KyokuyaSudokuContext,
  checkCompleted,
} from '@kyokuya/react-sudoku'
import HintIcon from '@mui/icons-material/EmojiObjects'
import GameRunningIcon from '@mui/icons-material/Pause'
import RefreshIcon from '@mui/icons-material/Refresh'
import TimerIcon from '@mui/icons-material/Timer'
import VisibilityIcon from '@mui/icons-material/Visibility'
import {
  Button,
  Dialog,
  DialogActions,
  DialogContent,
  IconButton,
  MenuItem,
  Modal,
  Select,
  Slider,
  Tooltip,
} from '@mui/material'
import cn from 'clsx'
import React, { useCallback, useContext, useEffect, useRef, useState } from 'react'
import { KyokuyaSudokuGameInput } from './SudokuGameInput'
import { KyokuyaSudokuGameOverlay } from './SudokuGameOverlay'
import './style.styl'

export const KyokuyaSudokuGameMain: React.FC = () => {
  const {
    SUDOKU_SIZE_SQRT,
    puzzle,
    solution,
    attempt,
    difficulty,
    radix,
    score,
    gameStatus,
    attemptTick,
    dispatch,
  } = useContext(KyokuyaSudokuContext)

  const containerRef = useRef<HTMLDivElement>(null)
  const sudokuValueRef = useRef<string>('')

  const [inputDialogVisible, setInputDialogVisible] = useState<boolean>(false)
  const [solutionVisible, setSolutionVisible] = useState<boolean>(false)
  const [restartDialogVisible, setRestartDialogVisible] = useState<boolean>(false)

  // Restart game.
  const restartGame = useCallback(() => {
    setRestartDialogVisible(false)
    dispatch({ type: KyokuyaSudokuActionType.RESTART })
  }, [dispatch])

  // Pause game.
  const pauseGame = useCallback(() => dispatch({ type: KyokuyaSudokuActionType.PAUSE }), [dispatch])

  const handleInput = useCallback(
    (text: string) => {
      setInputDialogVisible(false)
      sudokuValueRef.current = text

      const value = /^\s*$/.test(text) ? 0 : Number.parseInt(text, radix)
      if (Number.isInteger(value)) {
        dispatch({ type: KyokuyaSudokuActionType.INPUT, payload: value - 1 })
      }
    },
    [dispatch, radix],
  )
  const handleCellClick = useCallback(
    (r: number, c: number) => {
      if (r === -1 || c === -1 || puzzle[r][c] !== -1) return
      setInputDialogVisible(true)
    },
    [puzzle],
  )

  // Calc the score
  const usedTime: number = useElapsedTime(gameStatus)
  const SUDOKU_SIZE: number = SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT

  useEffect(() => {
    const isCompleted: boolean = checkCompleted(SUDOKU_SIZE, attempt, solution)
    if (!isCompleted) return

    let score = 0
    const totalTime: number = SUDOKU_SIZE_SQRT ** 4 * 1000
    if (usedTime < totalTime) {
      const totalScore: number = (SUDOKU_SIZE_SQRT ** 4 * difficulty) / 100
      score = ((totalTime - usedTime) * totalScore) / 1000
    }
    dispatch({
      type: KyokuyaSudokuActionType.FINISHED,
      payload: score,
    })
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [attemptTick])

  return (
    <div
      ref={containerRef}
      className={cn(
        'kyokuya-sudoku-game',
        `kyokuya-sudoku-game__${gameStatus}`,
        `kyokuya-sudoku-game__${SUDOKU_SIZE}x${SUDOKU_SIZE}`,
      )}
    >
      <div className="kyokuya-sudoku-game__wrapper">
        <div className="kyokuya-sudoku-game__toolbar">
          <div className="kyokuya-sudoku-game__toolbar-item">
            <span>Size:</span>
            <Select
              variant="standard"
              value={SUDOKU_SIZE_SQRT}
              disabled={gameStatus !== GameRunningStatus.PENDING}
              onChange={e =>
                dispatch({
                  type: KyokuyaSudokuActionType.RESET,
                  payload: {
                    SUDOKU_SIZE_SQRT: Number(e.target.value) as 2 | 3 | 4,
                  },
                })
              }
            >
              <MenuItem value={2}>4x4</MenuItem>
              <MenuItem value={3}>9x9</MenuItem>
              <MenuItem value={4}>16x16</MenuItem>
            </Select>
          </div>
          <div className="kyokuya-sudoku-game__toolbar-item">
            <span>Radix:</span>
            <Select
              variant="standard"
              value={radix}
              disabled={gameStatus !== GameRunningStatus.PENDING}
              onChange={e =>
                dispatch({
                  type: KyokuyaSudokuActionType.RESET,
                  payload: { radix: Number(e.target.value) as 10 | 16 },
                })
              }
            >
              <MenuItem value={10}>Decimal (x10)</MenuItem>
              <MenuItem value={16}>Hexadecimal (x16)</MenuItem>
            </Select>
          </div>
          <div className="kyokuya-sudoku-game__toolbar-item kyokuya-sudoku-game__toolbar-item-difficulty">
            <span>Difficulty:</span>
            <Slider
              value={difficulty}
              disabled={gameStatus !== GameRunningStatus.PENDING}
              step={1}
              min={0}
              max={100}
              valueLabelDisplay="auto"
              aria-labelledby="sudoku-difficulty"
              onChange={(e, v) =>
                dispatch({
                  type: KyokuyaSudokuActionType.RESET,
                  payload: { difficulty: v as number },
                })
              }
            />
          </div>
          <div className="kyokuya-sudoku-game__toolbar-item kyokuya-sudoku-game__toolbar-item-buttons">
            <Button
              variant="contained"
              color="inherit"
              startIcon={<RefreshIcon />}
              onClick={() =>
                gameStatus === GameRunningStatus.PENDING ||
                gameStatus === GameRunningStatus.FINISHED
                  ? restartGame()
                  : setRestartDialogVisible(true)
              }
            >
              New
            </Button>
            <Button
              variant="contained"
              color="inherit"
              disabled={gameStatus !== 'running'}
              startIcon={<HintIcon />}
              onClick={() => dispatch({ type: KyokuyaSudokuActionType.HINT })}
            >
              HINT
            </Button>
            <Button
              variant="contained"
              color="secondary"
              disabled={gameStatus !== 'running'}
              startIcon={<VisibilityIcon />}
              onClick={() => setSolutionVisible(true)}
            >
              Cheat
            </Button>
          </div>
          <div className="kyokuya-sudoku-game__toolbar-item kyokuya-sudoku-game__toolbar-item-state">
            <div key="state-buttons" className="kyokuya-sudoku-game__toolbar-state-buttons">
              {gameStatus === 'running' && (
                <Tooltip title="Pause">
                  <IconButton color="primary" onClick={pauseGame}>
                    <GameRunningIcon />
                  </IconButton>
                </Tooltip>
              )}
            </div>
            <div key="elapsed-time" className="kyokuya-sudoku-game__toolbar-elapsed-time">
              <Tooltip title="Time used">
                <TimerIcon />
              </Tooltip>
              &nbsp;&nbsp;
              <ElapsedTimer gameStatus={gameStatus} />
            </div>
            <div key="score" className="kyokuya-sudoku-game__toolbar-score">
              Score: {score}
            </div>
          </div>
        </div>
        <div className="kyokuya-sudoku-game__main">
          <KyokuyaSudoku
            overlay={<KyokuyaSudokuGameOverlay />}
            SolutionBoard={({ children }) => (
              <Modal
                open={solutionVisible}
                container={containerRef.current}
                keepMounted={true}
                disableAutoFocus={true}
                BackdropProps={{ timeout: 500 }}
                closeAfterTransition={true}
                onClose={() => setSolutionVisible(false)}
              >
                <div
                  className="kyokuya-sudoku-game__solution-wrapper"
                  onClick={() => setSolutionVisible(false)}
                >
                  <span className="kyokuya-sudoku-game__solution-close">&times;</span>
                  <div onClick={e => e.stopPropagation()}>{children}</div>
                </div>
              </Modal>
            )}
            onCellClick={handleCellClick}
          />
        </div>
      </div>
      <KyokuyaSudokuGameInput
        container={containerRef.current}
        initialValue={sudokuValueRef.current}
        visible={inputDialogVisible}
        label={`A ${radix === 10 ? 'decimal' : 'hexadecimal'} number`}
        onCancel={() => setInputDialogVisible(false)}
        onConfirm={handleInput}
      />
      <Dialog
        container={containerRef.current}
        open={restartDialogVisible}
        onClose={() => setRestartDialogVisible(false)}
        aria-labelledby="confirm-to-restart"
      >
        <DialogContent>Are you sure you want to start a new game?</DialogContent>
        <DialogActions>
          <Button color="inherit" onClick={() => setRestartDialogVisible(false)}>
            Cancel
          </Button>
          <Button color="primary" onClick={restartGame}>
            Confirm
          </Button>
        </DialogActions>
      </Dialog>
    </div>
  )
}
