import React from 'react'
import type { IKyokuyaSudokuAction } from './action'
import type { IKyokuyaSudokuState } from './state'
import { initKyokuyaSudokuState } from './state'

/**
 * Side-effect funcs provided by the KyokuyaSudokuContext.
 */
export interface IKyokuyaSudokuContext extends IKyokuyaSudokuState {
  /**
   * Update the context data.
   */
  dispatch: React.Dispatch<IKyokuyaSudokuAction>
}

/**
 * Create sudoku context.
 */
export const KyokuyaSudokuContext: React.Context<IKyokuyaSudokuContext> = React.createContext({
  ...initKyokuyaSudokuState(),
  dispatch: (): never => {
    throw new Error(`No available dispatch prepared yet.`)
  },
} as IKyokuyaSudokuContext)
