import invariant from '@guanghechen/invariant'
import cn from 'clsx'
import PropTypes from 'prop-types'
import React, { useContext } from 'react'
import { KyokuyaSudokuContext } from '../context/context'
import KyokuyaSudokuBoard from './SudokuBoard'
import './style.styl'

export interface IKyokuyaSudokuProps {
  /**
   * Sudoku board overlay.
   */
  overlay?: React.ReactNode
  /**
   * The solution Sudo-Board Renderer.
   * @param board
   */
  SolutionBoard?: React.FC<{ children: React.ReactElement }>
  /**
   * Callback function triggered when a grid is clicked.
   */
  onCellClick?(r: number, c: number): void
}

export const KyokuyaSudoku: React.FC<IKyokuyaSudokuProps> = props => {
  const { SUDOKU_SIZE_SQRT, gameStatus, solution, attempt, duplicatedMap } =
    useContext(KyokuyaSudokuContext)

  invariant(
    SUDOKU_SIZE_SQRT >= 2 && SUDOKU_SIZE_SQRT <= 7,
    '`childMatrixSize` must be an integer in the range [2, 7].',
  )

  const { overlay, SolutionBoard = () => null, onCellClick } = props
  return (
    <div className={cn('kyokuya-sudoku', `kyokuya-sudoku--${gameStatus}`)}>
      <KyokuyaSudokuBoard
        className="kyokuya-sudoku__board--puzzle"
        attempt={attempt}
        duplicatedMap={duplicatedMap}
        overlay={overlay}
        onCellClick={onCellClick}
      />
      <SolutionBoard>
        <KyokuyaSudokuBoard className="kyokuya-sudoku__board--solution" attempt={solution} />
      </SolutionBoard>
    </div>
  )
}

KyokuyaSudoku.propTypes = {
  overlay: PropTypes.node,
  SolutionBoard: PropTypes.any,
  onCellClick: PropTypes.func,
}

KyokuyaSudoku.displayName = 'KyokuyaSudoku'
export default KyokuyaSudoku
