import type { SudokuBoard } from '@algorithm.ts/sudoku'

export { SudokuSolver, SudokuCreator, createSudokuBoard } from '@algorithm.ts/sudoku'

/**
 * Check if a puzzle is valid
 * @param puzzle
 * @param SUDOKU_SIZE_SQRT
 * @returns
 */
export function checkPuzzle(puzzle: SudokuBoard, SUDOKU_SIZE_SQRT: number): boolean {
  const SUDOKU_SIZE = SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT
  if (puzzle.length !== SUDOKU_SIZE) return false
  for (const row of puzzle) {
    if (row.length !== SUDOKU_SIZE) return false
    for (const cell of row) {
      if (cell < -1 || cell >= SUDOKU_SIZE) return false
    }
  }
  return true
}
