import { createLocalStoreStorage } from '@kyokuya/react-storage'
import type { IKyokuyaSudokuState } from '@kyokuya/react-sudoku'
import { KyokuyaSudokuContext, initKyokuyaSudokuState, reducer } from '@kyokuya/react-sudoku'
import PropTypes from 'prop-types'
import React, { useMemo, useReducer } from 'react'
import { KyokuyaSudokuGameMain } from './SudokuGameMain'
import { useKyokuyaSudokuStatePersistEffect } from './useKyokuyaSudokuStatePersistEffect'

export const KyokuyaSudokuGame: React.FC<{
  storageKey?: string
  initialContextData?: Partial<IKyokuyaSudokuState>
}> = props => {
  const { storageKey, initialContextData } = props

  const storage = useMemo(
    () =>
      storageKey ? createLocalStoreStorage<Partial<IKyokuyaSudokuState>>(storageKey, JSON) : null,
    [storageKey],
  )

  const [state, dispatch] = useReducer(
    reducer,
    () => ({
      ...(storage == null ? {} : storage.load()),
      ...initialContextData,
    }),
    initKyokuyaSudokuState,
  )

  useKyokuyaSudokuStatePersistEffect(storage, state)

  return (
    <KyokuyaSudokuContext.Provider value={{ ...state, dispatch }}>
      <KyokuyaSudokuGameMain />
    </KyokuyaSudokuContext.Provider>
  )
}

KyokuyaSudokuGame.propTypes = {
  storageKey: PropTypes.string,
  initialContextData: PropTypes.any,
}
